from zh_copilot.replay.parser import parse_replay
from zh_copilot.replay.message_types import MsgType, ACTION_CATEGORIES
from collections import Counter
import os

all_msg_types = Counter()
all_args_by_type = {}
total_crc = 0
for f in os.listdir('replays'):
    if f.endswith('.rep'):
        r = parse_replay(f'replays/{f}')
        # count CRC separately 
        for cmd in r.commands:
            if cmd.is_crc:
                total_crc += 1
        for cmd in r.gameplay_commands:
            try:
                name = MsgType(cmd.msg_type).name
            except:
                name = f'UNKNOWN_{cmd.msg_type}'
            all_msg_types[name] += 1
            if name not in all_args_by_type and cmd.args:
                all_args_by_type[name] = {k.name: len(v) for k,v in cmd.args.items()}

print(f'CRC messages filtered: {total_crc}')
print()
print('Top 20 gameplay commands:')
for name, count in sorted(all_msg_types.items(), key=lambda x: -x[1])[:20]:
    args_info = all_args_by_type.get(name, {})
    cat = ACTION_CATEGORIES.get(getattr(MsgType, name, None), '-')
    print(f'  {count:5d}  {name:35s} cat={cat:12s} args={args_info}')
print()
print('Total gameplay commands:', sum(all_msg_types.values()))
print('Unique types:', len(all_msg_types))
